const items = $input.all().map(i => i.json).filter(j => j && j.id != null);
const lineas = items.map(j => '#' + j.id + ' [' + j.estado + '] ' + (j.titulo || '') + (j.fecha ? ' (' + j.fecha + ')' : ''));
const lista = lineas.join('\n');
const hay_ideas = lineas.length > 0;
const prompt_digest = hay_ideas
  ? [
      'Eres ResearchFlow. Redacta un digest semanal breve y motivador (maximo 200 palabras) para el propietario del sistema.',
      'Backlog de ideas de investigacion pendientes:',
      lista,
      '',
      'Incluye: 1) resumen del backlog en una frase, 2) cual idea recomiendas investigar primero y por que, 3) recordatorio de que puede lanzar con "investigar N" por WhatsApp.',
      'Texto plano, sin markdown.'
    ].join('\n')
  : 'Di exactamente: Tu backlog de ideas esta vacio esta semana. Manda cualquier idea al WhatsApp de ResearchFlow y la refinamos.';
return [{ json: { hay_ideas, lista, prompt_digest } }];

function extractText(r) {
  const parts = r?.candidates?.[0]?.content?.parts || [];
  return parts.map(p => p.text || '').join('\n').trim();
}
function extractCitas(r) {
  const out = [];
  const seen = new Set();
  const chunks = r?.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  for (const ch of chunks) {
    const web = ch.web || {};
    if (web.uri && !seen.has(web.uri)) { seen.add(web.uri); out.push({ titulo: web.title || web.uri, url: web.uri }); }
  }
  return out;
}
function parseJsonText(text) {
  if (!text) return null;
  let t = String(text).trim().replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
  try { return JSON.parse(t); } catch (e) {
    const m = t.match(/\{[\s\S]*\}/);
    if (m) { try { return JSON.parse(m[0]); } catch (e2) { return null; } }
    return null;
  }
}
const esc = (v) => String(v == null ? '' : v).replace(/'/g, "''");
const arr = (v) => Array.isArray(v) ? v : [];

const prev = $('Preparar digest').first().json;
const resp = $input.first().json || {};
let texto = extractText(resp);
if (!texto) {
  texto = prev.hay_ideas
    ? 'Ideas pendientes en tu backlog:\n' + prev.lista + '\n\nLanza una con "investigar N" por WhatsApp.'
    : 'Tu backlog de ideas esta vacio esta semana. Manda cualquier idea al WhatsApp de ResearchFlow.';
}
const email_html = '<div style="font-family:Segoe UI,Arial,sans-serif;max-width:640px;margin:auto"><h2>Digest semanal ResearchFlow</h2><p style="white-space:pre-wrap">' + texto.replace(/&/g, '&amp;').replace(/</g, '&lt;') + '</p></div>';
const whatsapp_text = ('ResearchFlow digest semanal:\n' + texto).slice(0, 900);
return [{ json: { email_html, whatsapp_text } }];
